 * Licensed under the Apache License, Version 2.0 (the "License").
 *
 * lievit-ui design tokens. Copied into the adopter's project by `lievit add <component>`
 * (first run only; merged on re-run). Components reference these by CSS custom property
 * name, never by hardcoded value, so a retheme is a token override in :root, not a
 * component edit (ADR-0005, ADR-0009).
 *
 * The --lv-* prefix is load-bearing: lievit-ui co-exists with the adopter's own CSS and
 * with Tailwind's generated vars, so the namespace prevents collisions (research 4.2).
 *
 * v2 vocabulary (issue #428): a Filament/shadcn-grade token set. The structure mirrors
 * shadcn-ui's new-york-v4 theme mapped to the --lv-* namespace: a full semantic colour
 * set (primary/secondary/muted/accent/destructive + success/warning/info, each with a
 * paired -fg), surfaces (card/popover), border/input/ring, a radius scale, a spacing
 * scale, a type scale (size/weight/line-height), shadows, z-index layers, motion
 * (duration + easing), and a chart palette.
 *
 * Colour FORMAT (v-next, architecture-contract §4 D1 DECIDED):
 * Source-of-truth is OKLCH (`oklch(L C H)`), the perceptually-uniform format with native
 * browser support in 2026. OKLCH buys predictable lightness for hover/active/disabled
 * states, easier WCAG-contrast math, and smoother programmatic tints — exactly what
 * Tailwind-UI-grade theming and dark-mode re-pointing need.
 *
 * Hex fallback pattern (chosen for simplicity over @supports):
 *   --lv-color-x: #hex;          ← old browsers (no oklch): keep this value
 *   --lv-color-x: oklch(L C H);  ← modern browsers: override via cascade
 * A plain double-declaration is the cleanest robust fallback: no wrapping block, no
 * extra selector specificity, idempotent under cascade. The hex values are
 * byte-identical to the pre-migration values so the look is visually unchanged.
 *
 * The brand-able seam: an adopter rebrands by overriding ~20 tokens in :root (chiefly the
 * semantic colour pairs + --lv-radius + the fonts); every component follows automatically.
 *
 * DARK MODE: a single `.dark, [data-theme="dark"]` block re-points the colour tokens only
 * (the structural tokens -- spacing, radius, type, z, motion -- are theme-invariant and
 * never repeated). Toggle by adding `class="dark"` or `data-theme="dark"` on <html>.
 *
 * The 31 v0.1 names are kept byte-stable so the 28 existing components do not break; the
 * new tokens are additive. Where a new shadcn-style name is the canonical one and an old
 * name is a near-synonym, the old name is preserved and documented as an alias.
 */

:root {
  /* ----------------------------------------------------------------------- *
   * COLOUR -- semantic surfaces and text (OKLCH: lightness chroma hue)       *
   * ----------------------------------------------------------------------- */

  /* base page surface + body text */
  --lv-color-bg: #ffffff;
  --lv-color-bg: oklch(1.0000 0 0);
  --lv-color-fg: #111827;
  --lv-color-fg: oklch(0.2101 0.0318 264.67);

  /* a slightly raised neutral surface: table zebra, inset panels (research 4.2) */
  --lv-color-surface: #f9fafb;
  --lv-color-surface: oklch(0.9846 0.0018 248.57);
  --lv-color-surface-fg: #111827;
  --lv-color-surface-fg: oklch(0.2101 0.0318 264.67);

  /* hairlines, dividers, default control borders */
  --lv-color-border: #d1d5db;
  --lv-color-border: oklch(0.8717 0.0094 258.38);

  /* form-control border (separable from --lv-color-border for inputs) */
  --lv-color-input: #d1d5db;
  --lv-color-input: oklch(0.8717 0.0094 258.38);

  /* control border on hover (one emphasis step up from --lv-color-border) */
  --lv-color-border-hover: #9ca3af;
  --lv-color-border-hover: oklch(0.7137 0.0192 261.32);

  /* low-emphasis text: captions, placeholders, disabled labels */
  --lv-color-muted: #6b7280;
  --lv-color-muted: oklch(0.5510 0.0234 264.37);
  --lv-color-muted-fg: #6b7280;
  --lv-color-muted-fg: oklch(0.5510 0.0234 264.37);
  --lv-color-muted-bg: #f3f4f6; /* muted FILL (badge/skeleton background) */
  --lv-color-muted-bg: oklch(0.9670 0.0030 264.51);

  /* card + popover surfaces (shadcn parity; default to bg, overridable) */
  --lv-color-card: #ffffff;
  --lv-color-card: oklch(1.0000 0 0);
  --lv-color-card-fg: #111827;
  --lv-color-card-fg: oklch(0.2101 0.0318 264.67);
  --lv-color-popover: #ffffff;
  --lv-color-popover: oklch(1.0000 0 0);
  --lv-color-popover-fg: #111827;
  --lv-color-popover-fg: oklch(0.2101 0.0318 264.67);

  /* ----------------------------------------------------------------------- *
   * COLOUR -- brand + semantic intents (each intent carries a paired -fg)    *
   * ----------------------------------------------------------------------- */

  /* primary: the main call to action */
  --lv-color-primary: #2563eb;
  --lv-color-primary: oklch(0.5461 0.2153 262.89);
  --lv-color-primary-fg: #ffffff;
  --lv-color-primary-fg: oklch(1.0000 0 0);

  /* secondary: low-emphasis neutral action (shadcn secondary) */
  --lv-color-secondary: #f3f4f6;
  --lv-color-secondary: oklch(0.9670 0.0030 264.51);
  --lv-color-secondary-fg: #1f2937;
  --lv-color-secondary-fg: oklch(0.2781 0.0296 256.86);

  /* accent: hover/active tint for menu items, ghost surfaces (shadcn accent) */
  --lv-color-accent: #f3f4f6;
  --lv-color-accent: oklch(0.9670 0.0030 264.51);
  --lv-color-accent-fg: #1f2937;
  --lv-color-accent-fg: oklch(0.2781 0.0296 256.86);

  /* destructive: the shadcn name for danger (alias below kept for the 28) */
  --lv-color-destructive: #dc2626;
  --lv-color-destructive: oklch(0.5771 0.2151 27.32);
  --lv-color-destructive-fg: #ffffff;
  --lv-color-destructive-fg: oklch(1.0000 0 0);
  /* destructive-subtle: pale tint for error region backgrounds (v-next field/form, additive) */
  --lv-color-destructive-subtle: #fef2f2;
  --lv-color-destructive-subtle: oklch(0.97 0.012 20);

  /* status intents (gestionale completeness, research 4.2) */
  --lv-color-success: #16a34a;
  --lv-color-success: oklch(0.6270 0.1699 149.23);
  --lv-color-success-fg: #ffffff;
  --lv-color-success-fg: oklch(1.0000 0 0);
  --lv-color-warning: #d97706;
  --lv-color-warning: oklch(0.6659 0.1574 58.31);
  --lv-color-warning-fg: #ffffff;
  --lv-color-warning-fg: oklch(1.0000 0 0);
  --lv-color-info: #2563eb; /* aliases primary; kept distinct so a retheme can split them */
  --lv-color-info: oklch(0.5461 0.2153 262.89);
  --lv-color-info-fg: #ffffff;
  --lv-color-info-fg: oklch(1.0000 0 0);
  --lv-color-danger: #dc2626; /* alias of --lv-color-destructive; kept for the 28 v0.1 components */
  --lv-color-danger: oklch(0.5771 0.2151 27.32);
  --lv-color-danger-fg: #ffffff;
  --lv-color-danger-fg: oklch(1.0000 0 0);

  /* chart palette: a 5-step sequential ramp for data-viz (shadcn chart-1..5) */
  --lv-color-chart-1: #93c5fd;
  --lv-color-chart-1: oklch(0.8091 0.0957 251.83);
  --lv-color-chart-2: #3b82f6;
  --lv-color-chart-2: oklch(0.6231 0.1881 259.82);
  --lv-color-chart-3: #2563eb;
  --lv-color-chart-3: oklch(0.5461 0.2153 262.89);
  --lv-color-chart-4: #1d4ed8;
  --lv-color-chart-4: oklch(0.4882 0.2172 264.38);
  --lv-color-chart-5: #1e40af;
  --lv-color-chart-5: oklch(0.4244 0.1809 265.64);

  /* sidebar surface set (shadcn sidebar tokens; for the app-shell block) */
  --lv-color-sidebar: #f9fafb;
  --lv-color-sidebar: oklch(0.9846 0.0018 248.57);
  --lv-color-sidebar-fg: #111827;
  --lv-color-sidebar-fg: oklch(0.2101 0.0318 264.67);
  --lv-color-sidebar-border: #e5e7eb;
  --lv-color-sidebar-border: oklch(0.9276 0.0059 264.52);
  --lv-color-sidebar-accent: #f3f4f6;
  --lv-color-sidebar-accent: oklch(0.9670 0.0030 264.51);
  --lv-color-sidebar-accent-fg: #1f2937;
  --lv-color-sidebar-accent-fg: oklch(0.2781 0.0296 256.86);

  /* overlay scrim behind modal surfaces (dialog/drawer backdrop) */
  --lv-color-overlay: rgb(0 0 0 / 0.45);

  /* ----------------------------------------------------------------------- *
   * FIELD layout (v-next, additive)                                         *
   * ----------------------------------------------------------------------- */
  --lv-field-label-width: 8rem; /* default label column width for horizontal field layout */

  /* ----------------------------------------------------------------------- *
   * SPACING (4px / 0.25rem base scale)                                      *
   * ----------------------------------------------------------------------- */
  --lv-space-0: 0;
  --lv-space-px: 1px;
  --lv-space-1: 0.25rem;
  --lv-space-1-5: calc(var(--lv-space-1) * 1.5);   /* ~6px: slider track thickness md; half-unit filler */
  --lv-space-2: 0.5rem;
  --lv-space-3: 0.75rem;
  --lv-space-3-5: calc(var(--lv-space-3) * 1.167);  /* ~14px: slider thumb diameter sm */
  --lv-space-4: 1rem;
  --lv-space-4-5: calc(var(--lv-space-4) * 1.125);  /* ~18px: slider thumb diameter md */
  --lv-space-5: 1.25rem;
  --lv-space-5-5: calc(var(--lv-space-5) * 1.1);    /* ~22px: slider thumb diameter lg */
  --lv-space-6: 1.5rem;
  --lv-space-7: 1.75rem; /* switch lg thumb diameter (28px); fills the gap between space-6 and space-8 */
  --lv-space-8: 2rem;
  --lv-space-20: 5rem; /* 80px: avatar 2xl diameter */
  --lv-space-9: 2.25rem; /* 36px: the shadcn h-9 control baseline (md form-control height) */
  --lv-space-10: 2.5rem;
  --lv-space-12: 3rem;
  --lv-space-16: 4rem;

  /* ----------------------------------------------------------------------- *
   * RADIUS scale (shadcn derives sm/md/lg from a single --lv-radius base)    *
   * ----------------------------------------------------------------------- */
  --lv-radius: 0.5rem; /* the brand-able base; override this to round everything */
  --lv-radius-sm: 0.25rem;
  --lv-radius-md: 0.5rem;
  --lv-radius-lg: 0.75rem;
  --lv-radius-xl: 1rem;
  --lv-radius-full: 9999px;

  /* ----------------------------------------------------------------------- *
   * TYPOGRAPHY                                                              *
   * ----------------------------------------------------------------------- */
  --lv-font-sans: system-ui, -apple-system, "Segoe UI", Roboto, sans-serif;
  --lv-font-mono: ui-monospace, "SF Mono", "Cascadia Code", "Roboto Mono", monospace;

  /* size scale */
  --lv-text-2xs: 0.625rem; /* 10px: avatar xs initials / xs icon */
  --lv-text-xs: 0.75rem;
  --lv-text-sm: 0.875rem;
  --lv-text-base: 1rem;
  --lv-text-lg: 1.125rem;
  --lv-text-xl: 1.25rem;
  --lv-text-2xl: 1.5rem;
  --lv-text-3xl: 1.875rem;
  --lv-text-4xl: 2.25rem;

  /* weights */
  --lv-font-normal: 400;
  --lv-font-medium: 500;
  --lv-font-semibold: 600;
  --lv-font-bold: 700;

  /* line-heights (--lv-leading kept as the default body alias) */
  --lv-leading: 1.5;
  --lv-leading-none: 1;
  --lv-leading-tight: 1.25;
  --lv-leading-normal: 1.5;
  --lv-leading-relaxed: 1.625;

  /* ----------------------------------------------------------------------- *
   * ELEVATION (shadow ramp; sm/md kept byte-stable for the 28)              *
   * ----------------------------------------------------------------------- */
  --lv-shadow-xs: 0 1px 2px 0 rgb(0 0 0 / 0.04);
  --lv-shadow-sm: 0 1px 2px 0 rgb(0 0 0 / 0.05);
  --lv-shadow-md: 0 4px 6px -1px rgb(0 0 0 / 0.07);
  --lv-shadow-lg: 0 10px 15px -3px rgb(0 0 0 / 0.1);
  --lv-shadow-xl: 0 20px 25px -5px rgb(0 0 0 / 0.1);

  /* ----------------------------------------------------------------------- *
   * FOCUS RING -- shared by every interactive primitive                     *
   * ----------------------------------------------------------------------- */
  --lv-color-ring: #2563eb; /* the ring colour token (shadcn --ring) */
  --lv-color-ring: oklch(0.5461 0.2153 262.89);
  --lv-ring: 0 0 0 3px color-mix(in srgb, var(--lv-color-ring) 35%, transparent);
  /* invalid/destructive focus ring: same geometry as --lv-ring, destructive hue */
  --lv-ring-destructive: 0 0 0 3px color-mix(in srgb, var(--lv-color-destructive) 35%, transparent);

  /* ----------------------------------------------------------------------- *
   * Z-INDEX layers (stacking contract for overlays)                         *
   * ----------------------------------------------------------------------- */
  --lv-z-base: 0;
  --lv-z-dropdown: 1000;
  --lv-z-sticky: 1100;
  --lv-z-overlay: 1200; /* dialog/drawer backdrop */
  --lv-z-modal: 1300; /* dialog/drawer panel */
  --lv-z-popover: 1400; /* popover/menu floating layer */
  --lv-z-tooltip: 1450; /* tooltip: above popover/menu, below toast; theme-invariant structural token (v-next, NET-NEW) */
  --lv-z-toast: 1500; /* always on top */

  /* ----------------------------------------------------------------------- *
   * OPACITY                                                                  *
   * ----------------------------------------------------------------------- */
  --lv-opacity-disabled: 0.5; /* dimming for disabled interactive controls (shadcn disabled:opacity-50) */

  /* ----------------------------------------------------------------------- *
   * MOTION (duration + easing for transitions/animations)                   *
   * ----------------------------------------------------------------------- */
  --lv-duration-fast: 120ms;
  --lv-duration: 200ms;
  --lv-duration-slow: 320ms;
  --lv-ease: cubic-bezier(0.4, 0, 0.2, 1); /* standard */
  --lv-ease-in: cubic-bezier(0.4, 0, 1, 1);
  --lv-ease-out: cubic-bezier(0, 0, 0.2, 1);
  /* component-specific motion tokens (net-new, additive; set to `none` by prefers-reduced-motion) */
  --lv-motion-switch-thumb: transform 120ms ease; /* switch thumb slide; separate from --lv-duration-fast so timing is tunable per-component */

  /* progress motion aliases (net-new, additive; alias the shared duration/ease tokens so the
     progress animation can be tuned independently of the global scale) */
  --lv-motion-duration-slow: 320ms; /* = --lv-duration-slow; aliased for progress indeterminate */
  --lv-motion-easing-in-out: cubic-bezier(0.4, 0, 0.2, 1); /* = --lv-ease; aliased for progress */
  /* loading-section motion aliases (net-new, additive) */
  --lv-motion-duration-base: 200ms; /* = --lv-duration; alias for spinner rotation duration */
  --lv-motion-easing-linear: linear; /* linear easing for spinner + skeleton shimmer */
  --lv-pointer-events-none: none; /* pointer-events value; structural, not colour-dependent */

  /* skeleton tokens (net-new, loading-section spec §5) */
  --lv-skeleton-bg: oklch(0.93 0.005 264); /* placeholder bar fill -- light mode */
  --lv-skeleton-shimmer: oklch(0.97 0.003 264); /* shimmer highlight peak -- light mode */

  /* ----------------------------------------------------------------------- *
   * ICON sizing (consumed by the Lucide icon partial)                       *
   * ----------------------------------------------------------------------- */
  --lv-icon-size: 1em; /* inherit text size by default; currentColor strokes it */
  --lv-icon-stroke: 2; /* Lucide's native stroke width */
}

/* ========================================================================= *
 * DARK MODE -- re-points colour tokens only. Structural tokens (spacing,    *
 * radius, type, z, motion, icon) are theme-invariant and never repeated.    *
 * Activate with class="dark" or data-theme="dark" on a root element.        *
 * ========================================================================= */
.dark,
[data-theme="dark"] {
  --lv-color-bg: #0a0a0a;
  --lv-color-bg: oklch(0.1448 0 0);
  --lv-color-fg: #fafafa;
  --lv-color-fg: oklch(0.9851 0 0);

  --lv-color-surface: #171717;
  --lv-color-surface: oklch(0.2046 0 0);
  --lv-color-surface-fg: #fafafa;
  --lv-color-surface-fg: oklch(0.9851 0 0);

  --lv-color-border: #2e2e2e;
  --lv-color-border: oklch(0.3012 0 0);
  --lv-color-input: #3a3a3a;
  --lv-color-input: oklch(0.3485 0 0);
  --lv-color-border-hover: #4a4a4a;
  --lv-color-border-hover: oklch(0.4310 0 0);

  --lv-color-muted: #a1a1aa;
  --lv-color-muted: oklch(0.7118 0.0130 285.96);
  --lv-color-muted-fg: #a1a1aa;
  --lv-color-muted-fg: oklch(0.7118 0.0130 285.96);
  --lv-color-muted-bg: #262626;
  --lv-color-muted-bg: oklch(0.2686 0 0);

  --lv-color-card: #171717;
  --lv-color-card: oklch(0.2046 0 0);
  --lv-color-card-fg: #fafafa;
  --lv-color-card-fg: oklch(0.9851 0 0);
  --lv-color-popover: #171717;
  --lv-color-popover: oklch(0.2046 0 0);
  --lv-color-popover-fg: #fafafa;
  --lv-color-popover-fg: oklch(0.9851 0 0);

  --lv-color-primary: #3b82f6;
  --lv-color-primary: oklch(0.6231 0.1881 259.82);
  --lv-color-primary-fg: #0a0a0a;
  --lv-color-primary-fg: oklch(0.1448 0 0);

  --lv-color-secondary: #262626;
  --lv-color-secondary: oklch(0.2686 0 0);
  --lv-color-secondary-fg: #fafafa;
  --lv-color-secondary-fg: oklch(0.9851 0 0);

  --lv-color-accent: #2e2e2e;
  --lv-color-accent: oklch(0.3012 0 0);
  --lv-color-accent-fg: #fafafa;
  --lv-color-accent-fg: oklch(0.9851 0 0);

  --lv-color-destructive: #ef4444;
  --lv-color-destructive: oklch(0.6369 0.2078 25.32);
  --lv-color-destructive-fg: #fafafa;
  --lv-color-destructive-fg: oklch(0.9851 0 0);
  --lv-color-destructive-subtle: #2d1111;
  --lv-color-destructive-subtle: oklch(0.22 0.025 20);

  --lv-color-success: #22c55e;
  --lv-color-success: oklch(0.7227 0.1920 149.60);
  --lv-color-success-fg: #052e16;
  --lv-color-success-fg: oklch(0.2664 0.0628 152.96);
  --lv-color-warning: #f59e0b;
  --lv-color-warning: oklch(0.7686 0.1646 70.08);
  --lv-color-warning-fg: #1c1207;
  --lv-color-warning-fg: oklch(0.1921 0.0263 68.60);
  --lv-color-info: #3b82f6;
  --lv-color-info: oklch(0.6231 0.1881 259.82);
  --lv-color-info-fg: #0a0a0a;
  --lv-color-info-fg: oklch(0.1448 0 0);
  --lv-color-danger: #ef4444;
  --lv-color-danger: oklch(0.6369 0.2078 25.32);
  --lv-color-danger-fg: #fafafa;
  --lv-color-danger-fg: oklch(0.9851 0 0);

  --lv-color-chart-1: #1e3a8a;
  --lv-color-chart-1: oklch(0.3790 0.1378 265.53);
  --lv-color-chart-2: #1d4ed8;
  --lv-color-chart-2: oklch(0.4882 0.2172 264.38);
  --lv-color-chart-3: #2563eb;
  --lv-color-chart-3: oklch(0.5461 0.2153 262.89);
  --lv-color-chart-4: #3b82f6;
  --lv-color-chart-4: oklch(0.6231 0.1881 259.82);
  --lv-color-chart-5: #93c5fd;
  --lv-color-chart-5: oklch(0.8091 0.0957 251.83);

  --lv-color-sidebar: #171717;
  --lv-color-sidebar: oklch(0.2046 0 0);
  --lv-color-sidebar-fg: #fafafa;
  --lv-color-sidebar-fg: oklch(0.9851 0 0);
  --lv-color-sidebar-border: #2e2e2e;
  --lv-color-sidebar-border: oklch(0.3012 0 0);
  --lv-color-sidebar-accent: #262626;
  --lv-color-sidebar-accent: oklch(0.2686 0 0);
  --lv-color-sidebar-accent-fg: #fafafa;
  --lv-color-sidebar-accent-fg: oklch(0.9851 0 0);

  --lv-color-ring: #3b82f6;
  --lv-color-ring: oklch(0.6231 0.1881 259.82);

  /* shadows read darker on a dark canvas */
  --lv-shadow-xs: 0 1px 2px 0 rgb(0 0 0 / 0.3);
  --lv-shadow-sm: 0 1px 2px 0 rgb(0 0 0 / 0.4);
  --lv-shadow-md: 0 4px 6px -1px rgb(0 0 0 / 0.45);
  --lv-shadow-lg: 0 10px 15px -3px rgb(0 0 0 / 0.5);
  --lv-shadow-xl: 0 20px 25px -5px rgb(0 0 0 / 0.55);

  /* skeleton tokens (net-new, loading-section spec §5) -- dark-mode overrides */
  --lv-skeleton-bg: oklch(0.24 0.008 264); /* placeholder bar fill -- dark mode */
  --lv-skeleton-shimmer: oklch(0.30 0.006 264); /* shimmer highlight peak -- dark mode */
}

/* ========================================================================= *
 * REDUCED MOTION -- suppresses component-specific motion tokens when the OS  *
 * requests it. Structural tokens (spacing, radius, etc.) are unaffected.     *
 * ========================================================================= */
@media (prefers-reduced-motion: reduce) {
  :root {
    --lv-motion-switch-thumb: none; /* instant thumb swap instead of sliding transition */
  }
}

/* ========================================================================= *
 * PROGRESS ANIMATIONS (@keyframes referenced by progress.jte, CSP-clean)   *
 * Three animations: indeterminate-line slide, striped-line stripe-march,    *
 * and indeterminate-arc spin for the circle/dashboard forms.                *
 * Each is named lv-progress-* so they are namespaced and greppable.        *
 * motion-reduce:animate-none is applied at the component level; these rules *
 * are structural (not suppressed here) so they remain valid for adopters    *
 * who override the component class selectively.                             *
 * ========================================================================= */

/* lv-progress-slide: the indeterminate line bar -- a 40%-wide fill that slides
   from -40% to 100% (left edge off-screen left to right), giving the illusion
   of continuous progress. Duration + easing reference the motion alias tokens
   defined above so adopters can tune them via :root override. */
@keyframes lv-progress-slide {
  0%   { transform: translateX(-100%); }
  100% { transform: translateX(350%); }
}

/* lv-progress-stripe-move: marches the diagonal stripe repeating-linear-gradient
   to the right, creating a moving barber-pole effect on a striped determinate bar.
   The gradient background-size is 24px (2x the 12px stripe period from progress.jte),
   so stepping 24px recreates the full tile. */
@keyframes lv-progress-stripe-move {
  0%   { background-position: 0 0; }
  100% { background-position: 24px 0; }
}

/* lv-progress-arc-spin: rotates the short indeterminate arc in the circle/dashboard
   forms. Applied on the <circle> element directly; transform-origin is the SVG centre
   (60px 60px for the 120x120 viewBox). */
@keyframes lv-progress-arc-spin {
  0%   { transform: rotate(0deg); }
  100% { transform: rotate(360deg); }
}

/* lv-skeleton-shimmer: slides the gradient background-position left-to-right to produce
   the shimmer sweep. background-size must be 400% on the element so the gradient covers
   the range. Duration + easing reference the motion alias tokens so adopters can tune them
   via :root override. The animation name is lv-skeleton-* to match the lv-* namespace. */
@keyframes lv-skeleton-shimmer {
  0%   { background-position: -200% 0; }
  100% { background-position:  200% 0; }
}

